#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <iostream>

template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block_allocator instance
    hexi::detail::block_allocator<std::uint8_t, element_count> allocator;

    std::cout << "Demonstrating block_allocator free list management:\n";
    std::cout << "Initial state: Free list contains " << element_count << " blocks\n";

    // Demonstrate allocation (calls pop() internally)
    std::uint8_t* block1 = allocator.allocate();
    std::cout << "After allocate(): Free list size decreased by 1\n";

    // Demonstrate deallocation (calls push() internally)
    allocator.deallocate(block1);
    std::cout << "After deallocate(): Free list size increased by 1\n";

    // Demonstrate multiple allocations/deallocations
    std::uint8_t* blocks[element_count];

    // Allocate all blocks
    for (size_t i = 0; i < element_count; ++i) {
        blocks[i] = allocator.allocate();
    }
    std::cout << "After allocating all " << element_count << " blocks: Free list is empty\n";

    // Deallocate all blocks
    for (size_t i = 0; i < element_count; ++i) {
        allocator.deallocate(blocks[i]);
    }
    std::cout << "After deallocating all blocks: Free list contains " << element_count << " blocks\n";

    // Demonstrate the circular nature of the free list
    std::uint8_t* test_block = allocator.allocate();
    std::cout << "Allocated one block, then deallocate it...\n";
    allocator.deallocate(test_block);
    std::cout << "Free list now contains " << element_count << " blocks again\n";
}
```

