template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(const hexi::detail::intrusive_storage<block_size>& storage, size_t bytes_to_preview) {
    std::vector<uint8_t> preview_data(bytes_to_preview);

    // Use the copy function to preview data without advancing read pointer
    storage.copy(preview_data.data(), bytes_to_preview);

    return preview_data;
}

template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    BufferStatus<> status;

    // Use the size function to get readable data size
    status.readable_size = storage.size();

    // Calculate free space as block_size minus write_offset
    // Since write_offset is not directly accessible, we calculate based on block_size and current usage
    // The free space is the remaining capacity in the buffer
    status.free_space = 1024 - status.readable_size; // Assuming block_size=1024

    return status;
}

template<size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    // Set both read_offset and write_offset to 0
    // Since direct access to offsets is not provided, we need to use available methods
    // This implementation assumes we can manipulate the buffer through available interfaces

    // One way to reset: read all available data to advance read_offset to write_offset
    size_t available_data = storage.size();
    if (available_data > 0) {
        std::vector<uint8_t> temp_buffer(available_data);
        storage.read(temp_buffer.data(), available_data);
    }

    // Then write zero bytes to reset write_offset (this may vary based on actual implementation)
    // This is a simplified approach - actual reset mechanism may differ
    uint8_t dummy_byte = 0;
    storage.write(&dummy_byte, 0);
}
