std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // Create a buffer to hold the data
    std::vector<uint8_t> buffer;

    // Create buffer_write_adaptor for the buffer
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>> write_adaptor(buffer);

    // Check available space and write data
    if (write_adaptor.free() >= input_data.size()) {
        write_adaptor.write(input_data.data(), input_data.size());
    }

    // Create buffer_read_adaptor for the same buffer
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> read_adaptor(buffer);

    // Check readable size and read data back
    std::vector<uint8_t> output_data(read_adaptor.size());
    if (!output_data.empty()) {
        read_adaptor.read(output_data.data(), output_data.size());
    }

    return output_data;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data, std::size_t peek_size) {
    // Create buffer_read_adaptor for the buffer
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> adaptor(buffer_data);

    // Use copy() to peek at data without advancing read pointer
    std::vector<uint8_t> peeked_data(peek_size);
    if (peek_size <= adaptor.size()) {
        adaptor.copy(peeked_data.data(), peek_size);
    }

    // Use read_ptr() to get pointer and then read() to consume the data
    // This advances the read pointer
    if (!peeked_data.empty()) {
