    // Create binary_stream object from the input buffer
    hexi::binary_stream stream(buffer);

    // Read message_id and convert from big-endian to native
    uint32_t message_id;
    stream.read(&message_id);
    packet.message_id = hexi::endian::big_to_native(message_id);

    // Read data_values count and convert
